let cmdKey = false;
$(document).on('keydown', function(e) {
    if (!$(e.target).is('input')) {
        if ((e.metaKey || e.ctrlKey) && (String.fromCharCode(e.which).toLowerCase() === 'c')) {
            cmdKey = true;
            return;
        }
        var DKey = 68;
        var QKey = 81;
        var KKey = 75;
        var JKey = 74;
        var CKey = 67;
        var SKey = 83;
        var DotKey = 83;
        var RKey = 82;
        var EKey = 69;

        if (e.which === DKey && !e.ctrlKey) {
            if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                                    App.Defects.preparePush(1, 0, 'suites/view', 1);
                                }
        }

        if (e.which === QKey) {
            if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                if (!App.Ajax.isBusy()) {
                    App.QPane.tryToggleRow();
                }
            }
        }

        if (e.which === KKey) {
            if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                if (App.QPane.isVisible()) {
                    App.Suites.prevRow();
                }
            }
        }

        if (e.which === JKey) {
            if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                if (App.QPane.isVisible()) {
                    App.Suites.nextRow();
                }
            }
        }
                        if (e.which === CKey && !e.ctrlKey && cmdKey === false) {
                if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                    App.Page.load('cases/add/1');
                }
            }

            if (e.which === SKey) {
                if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                    if (App.Tables.group_by == 'cases:section_id' &&
                        App.Suites.display != 'tree')
                    {
                        App.Sections.addSub(1, App.Suites.group_id);
                    } else {
                        App.Sections.add(1);
                    }
                }
            }

            if (e.which === DotKey) {
                if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                    if (App.Tables.group_by == 'cases:section_id' &&
                        App.Suites.display != 'tree')
                    {
                        App.Cases.add(App.Suites.group_id);
                    }
                }
            }

                        if (e.which === RKey && !e.ctrlKey) {
                if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                    App.Page.load('runs/add/1/2');
                }
            }

                        if (e.which === EKey) {
                if (!$(e.target).hasClass('form-control-full') && !$(e.target).attr('contenteditable')) {
                                            App.Suites.editDescription(1);
                                        }
            }
                }
    setTimeout(
        function()
        {
            cmdKey = false;
        },
        2000
    );
});

